effect.shader:
void main() {

    vec4 maskColor = texture2DCv(inputImg.texture,acScreenNorm);
    float mask;
    if( channel==0 ) {
        mask = maskColor.r*0.2126 + maskColor.g*0.7152 + maskColor.b*0.0722;
    } else if( channel == 1 ) {
        mask = maskColor.r;
    } else if( channel == 2 ) {
        mask = maskColor.g;
    } else if( channel == 3 ) {
        mask = maskColor.b;
    } else {
        mask = maskColor.a;
    }

    if( acPass==0 ) {

        float angle = 0.0;
        float actualStrength = (strength/4.0) * mask;

        vec2 texelSize = 1.0 / vec2(comp.size);
        float rad = angle * 0.0174533;
        vec2 velocity = vec2(cos(rad)*actualStrength,-sin(rad)*actualStrength);
        float speed = length(velocity / texelSize);
        int nSamples = int(clamp(speed, 1.01, 100.01));
        vec4 outColor = texture2DCv(comp.texture,acScreenNorm.st);
        for(int i=1; i<nSamples; i++ ) {
            vec2 offset = velocity * (float(i) / float(nSamples - 1) - 0.5);
            outColor += texture2DCv(comp.texture, acScreenNorm.st-offset);
        }
        gl_FragColor = outColor/float(nSamples);

    } else {

        float angle = 90.0;
        float actualStrength = (strength/4.0) * mask;

        vec2 texelSize = 1.0 / vec2(comp.size);
        float rad = angle * 0.0174533;
        vec2 velocity = vec2(cos(rad)*actualStrength,-sin(rad)*actualStrength);
        float speed = length(velocity / texelSize);
        int nSamples = int(clamp(speed, 1.01, 100.01));
        vec4 outColor = texture2DCv(hblur.texture,acScreenNorm.st);
        for(int i=1; i<nSamples; i++ ) {
            vec2 offset = velocity * (float(i) / float(nSamples - 1) - 0.5);
            outColor += texture2DCv(hblur.texture, acScreenNorm.st-offset);
        }
        gl_FragColor = outColor/float(nSamples) * maskColor.a;

    }
}
